// Procesa actualizaciones de Telegram: maneja /start <token>
const body = items[0].json.body || items[0].json || {};
const message = body.message || {};
const chatId = String((message.chat && message.chat.id) || '');
const text = message.text || '';
const username = (message.from && (message.from.username || message.from.first_name)) || '';
if (!text || !text.startsWith('/start')) {
  return [{ json: { ok: true, note: 'no-start' } }];
}
const linkToken = text.replace('/start', '').trim();
if (!linkToken) {
  await this.helpers.request({ method: 'POST', uri: 'https://api.telegram.org/bot' + process.env.TELEGRAM_BOT_TOKEN + '/sendMessage', json: true, body: { chat_id: chatId, text: '👋 Bienvenido a MiTiendaVirtual. Vincula tu cuenta desde la app.' } });
  return [{ json: { ok: true, note: 'generic-sent' } }];
}
const SUPABASE_URL = process.env.SUPABASE_URL;
const SUPABASE_SERVICE_ROLE_KEY = process.env.SUPABASE_SERVICE_ROLE_KEY;
if (!SUPABASE_URL || !SUPABASE_SERVICE_ROLE_KEY) throw new Error('Supabase misconfigured');
const found = await this.helpers.request({ method: 'GET', uri: SUPABASE_URL + '/rest/v1/telegram_link_tokens?token=eq.' + encodeURIComponent(linkToken) + '&used=eq.false', headers: { apikey: SUPABASE_SERVICE_ROLE_KEY, Authorization: 'Bearer ' + SUPABASE_SERVICE_ROLE_KEY }, json: true });
if (!Array.isArray(found) || found.length === 0) {
  await this.helpers.request({ method: 'POST', uri: 'https://api.telegram.org/bot' + process.env.TELEGRAM_BOT_TOKEN + '/sendMessage', json: true, body: { chat_id: chatId, text: '⚠️ El enlace de vinculación no es válido o ya expiró. Genera uno nuevo desde la app.' } });
  return [{ json: { ok: true, note: 'token-not-found' } }];
}
const tokenRow = found[0];
if (tokenRow.expires_at && new Date(tokenRow.expires_at) <= new Date()) {
  await this.helpers.request({ method: 'POST', uri: 'https://api.telegram.org/bot' + process.env.TELEGRAM_BOT_TOKEN + '/sendMessage', json: true, body: { chat_id: chatId, text: '⚠️ El enlace expiró. Genera uno nuevo desde la app.' } });
  return [{ json: { ok: true, note: 'token-expired' } }];
}
await this.helpers.request({ method: 'PATCH', uri: SUPABASE_URL + '/rest/v1/telegram_link_tokens?id=eq.' + tokenRow.id, headers: { apikey: SUPABASE_SERVICE_ROLE_KEY, Authorization: 'Bearer ' + SUPABASE_SERVICE_ROLE_KEY, 'Content-Type': 'application/json' }, json: true, body: { used: true, chat_id: chatId, telegram_username: username } });
const existing = await this.helpers.request({ method: 'GET', uri: SUPABASE_URL + '/rest/v1/user_notification_configs?user_id=eq.' + tokenRow.user_id + '&channel_type=eq.telegram', headers: { apikey: SUPABASE_SERVICE_ROLE_KEY, Authorization: 'Bearer ' + SUPABASE_SERVICE_ROLE_KEY }, json: true });
const cfg = { telegram_chat_id: chatId, telegram_username: username, connected_at: new Date().toISOString() };
if (Array.isArray(existing) && existing.length > 0) {
  await this.helpers.request({ method: 'PATCH', uri: SUPABASE_URL + '/rest/v1/user_notification_configs?id=eq.' + existing[0].id, headers: { apikey: SUPABASE_SERVICE_ROLE_KEY, Authorization: 'Bearer ' + SUPABASE_SERVICE_ROLE_KEY, 'Content-Type': 'application/json' }, json: true, body: { is_active: true, config: cfg } });
} else {
  await this.helpers.request({ method: 'POST', uri: SUPABASE_URL + '/rest/v1/user_notification_configs', headers: { apikey: SUPABASE_SERVICE_ROLE_KEY, Authorization: 'Bearer ' + SUPABASE_SERVICE_ROLE_KEY, 'Content-Type': 'application/json' }, json: true, body: { user_id: tokenRow.user_id, channel_type: 'telegram', is_active: true, config: cfg } });
}
await this.helpers.request({ method: 'POST', uri: 'https://api.telegram.org/bot' + process.env.TELEGRAM_BOT_TOKEN + '/sendMessage', json: true, body: { chat_id: chatId, text: '✅ ¡Tu cuenta de MiTiendaVirtual fue vinculada exitosamente! Recibirás notificaciones aquí.' } });
return [{ json: { ok: true, note: 'linked' } }];
